import os
from sqlalchemy import create_engine

def establish_database():    
    db_user = os.getenv('DB_USER', 'admin')  # get DB user from env vars if available else use default value  
    password = os.getenv('PASSWORD','demo123')      # same for the database's password, using environment variables after demo setup    
                                                                              
    engine=create_engine(f"postgresql://{db_user}:{password}@localhost:5432/hackathon_db")  # create an instance of a DB Engine  
     
    return engine                                                   # returning the database's connection object.